function linFit(x, y) {
	let SXi2 = 0;
	let SXi = 0;
	let SXiYi = 0;
	let SYi = 0;
	let n = x.length;
	for (let i = 0; i < n; i++) {
		SXi = SXi + x[i];
		SXi2 = SXi2 + x[i] * x[i];
		SYi = SYi + y[i];
		SXiYi = SXiYi + x[i] * y[i];
	}
	let det_A = SXi2 * n - SXi * SXi;
	let m = 0;
	let b = y[0];
	if (det_A != 0) {
		m = (SXiYi * n - SXi * SYi) / det_A;
		b = (SXi2 * SYi - SXiYi * SXi) / det_A;
	}
	return [m, b];
}

function numAverage(a) {
  var b = a.length,
      c = 0, i;
  for (i = 0; i < b; i++){
    c += Number(a[i]);
  }
  return Math.round(c/b);
}

