for (let i = 1; i < altitude.length; i++) {
    const distDiff = distance[i] - distance[i - 1];
    const altDiff = altitude[i] - altitude[i - 1];
    const gradeValue = grade[i];

    if (gradeValue >= MIN_GRADE) {
