            currentClimb.startIndex = i - 1;
            currentClimb.startTime = time[i - 1]; // Temps de départ
        }
        currentClimb.endIndex = i;
        currentClimb.distance += distDiff;
        currentClimb.elevation += altDiff;
        currentClimb.endTime = time[i]; // Temps de fin
    } else if (currentClimb.startIndex !== null) {
        climbs.push({ ...currentClimb });
        currentClimb = { startIndex: null, endIndex: null, distance: 0, elevation: 0, startTime: null, endTime: null };
    }
}

// Fusionner les montées proches
for (let i = 1; i < climbs.length; i++) {
    if (climbs[i].startTime - climbs[i - 1].endTime <= GAP_TIME_THRESHOLD) {
        climbs[i - 1].endIndex = climbs[i].endIndex;
        climbs[i - 1].distance += climbs[i].distance;
        climbs[i - 1].elevation += climbs[i].elevation;
        climbs[i - 1].endTime = climbs[i].endTime;
        climbs.splice(i, 1);
        i--;
    }
}

// Filtrer les montées qui respectent les critères après fusion
climbs = climbs.filter(climb => climb.distance >= MIN_DISTANCE && climb.elevation >= MIN_ELEVATION_GAIN);

// Traiter les montées détectées
climbs.forEach(climb => {
    const climbGrades = grade.slice(climb.startIndex, climb.endIndex + 1);
    const climbPowers = power.slice(climb.startIndex, climb.endIndex + 1);
    const climbHRs = heartrate.slice(climb.startIndex, climb.endIndex + 1);

    const avgGrade = climbGrades.reduce((a, b) => a + b, 0) / climbGrades.length;
    const avgPower = climbPowers.reduce((a, b) => a + b, 0) / climbPowers.length;
    const avgHR = climbHRs.reduce((a, b) => a + b, 0) / climbHRs.length;
    const maxHR = Math.max(...climbHRs);
    const maxgrade = Math.max(...climbGrades);

    const climbTimeInSeconds = climb.endTime - climb.startTime;
    const formattedTime = `${Math.floor(climbTimeInSeconds / 60)}min${climbTimeInSeconds % 60}s`;

    const ascentSpeed = climb.elevation / (climbTimeInSeconds / 3600);
    const avgHorizontalSpeed = (climb.distance / 1000) / (climbTimeInSeconds / 3600);

    const difficultyCoefficient = Math.pow(avgGrade, 2) * (climb.distance / 1000);

    if (difficultyCoefficient < 5) {
        return;
    }

    let bgColor = "silver";
    if (difficultyCoefficient >= 25 && difficultyCoefficient < 75) bgColor = "yellowgreen";
    else if (difficultyCoefficient >= 75 && difficultyCoefficient < 150) bgColor = "orange";
    else if (difficultyCoefficient >= 150 && difficultyCoefficient < 300) bgColor = "orangered";
    else if (difficultyCoefficient >= 300 && difficultyCoefficient < 600) bgColor = "firebrick";
    else if (difficultyCoefficient >= 600 && difficultyCoefficient < 900) bgColor = "indigo";
    else if (difficultyCoefficient >= 900) bgColor = "black";

    traces.push({
        x: distanceKm.slice(climb.startIndex, climb.endIndex + 1),
        y: altitude.slice(climb.startIndex, climb.endIndex + 1),
        type: 'scatter',
        mode: 'lines',
        line: { color: bgColor, width: 2 },
        name: `Montée`,
        hoverinfo: 'text',
        text: climbGrades.map((_, i) =>
            `D+: ${climb.elevation.toFixed(1)} m<br>
            Distance: ${(climb.distance / 1000).toFixed(1)} km<br>
            % moyen: ${avgGrade.toFixed(1)}%<br>
            % max: ${maxgrade.toFixed(1)}%<br>
            Vitesse ascensionnelle: ${ascentSpeed.toFixed(1)} m/h<br>
            Vitesse moyenne: ${avgHorizontalSpeed.toFixed(1)} km/h<br> 
            Puissance moy.: ${avgPower.toFixed(0)} W<br>
            FC moy.: ${avgHR.toFixed(0)} bpm<br>
            FC max: ${maxHR} bpm<br>
            Temps de montée: ${formattedTime}`
        )
    });

    annotations.push({
        x: (distanceKm[climb.startIndex] + distanceKm[climb.endIndex]) / 2,
        y: Math.max(...altitude) + 50,
        text: `${Math.round(difficultyCoefficient)}`,
        showarrow: false,
        font: { family: 'Arial', size: 16, color: 'white' },
        align: 'center',
        bgcolor: bgColor,
        bordercolor: difficultyCoefficient > 900 ? 'red' : null,
        borderwidth: difficultyCoefficient > 900 ? 2 : 0,
        opacity: 0.9
    });
});

traces.unshift({ x: distanceKm, y: altitude, fill: 'tozeroy', type: 'scatter', fillcolor: 'whitesmoke', mode: 'none', name: 'Altitude' });
layout = { title: 'Profil d\'Altitude avec Montées', xaxis: { title: 'Distance (km)' }, yaxis: { title: 'Altitude (m)' }, annotations: annotations, hovermode: 'x unified', showlegend: false };
chart = { data: traces, layout };
chart;

{
    const activity = icu.activity;
